	private void saveSummary(M_SRWA_12H_Summary_Entity e) {
		Object[] rVals = rFieldValues(e);
		Object[] params = new Object[rVals.length + 9];
		System.arraycopy(rVals, 0, params, 0, rVals.length);
		params[rVals.length] = e.getReportVersion();
		params[rVals.length + 1] = e.getReportResubDate();
		params[rVals.length + 2] = e.getREPORT_FREQUENCY();
		params[rVals.length + 3] = e.getREPORT_CODE();
		params[rVals.length + 4] = e.getREPORT_DESC();
		params[rVals.length + 5] = e.getENTITY_FLG();
		params[rVals.length + 6] = e.getMODIFY_FLG();
		params[rVals.length + 7] = e.getDEL_FLG();
		params[rVals.length + 8] = e.getReportDate();
		jdbcTemplate.update(
				"UPDATE BRRS_M_SRWA_12H_SUMMARYTABLE SET " + R_FIELDS_SET
						+ ",REPORT_VERSION=?,REPORT_RESUBDATE=?,REPORT_FREQUENCY=?,REPORT_CODE=?,REPORT_DESC=?,ENTITY_FLG=?,MODIFY_FLG=?,DEL_FLG=?"
						+ " WHERE REPORT_DATE=?",
				params);
	}

	private void saveDetail(M_SRWA_12H_Detail_Entity e) {
		int cnt = jdbcTemplate.queryForObject("SELECT COUNT(*) FROM BRRS_M_SRWA_12H_DETAILTABLE WHERE REPORT_DATE=?",
				new Object[] { e.getReportDate() }, Integer.class);
		Object[] rVals = rFieldValues(e);
		if (cnt > 0) {
			Object[] params = new Object[rVals.length + 9];
			System.arraycopy(rVals, 0, params, 0, rVals.length);
			params[rVals.length] = e.getReportVersion();
			params[rVals.length + 1] = e.getReportResubDate();
			params[rVals.length + 2] = e.getREPORT_FREQUENCY();
			params[rVals.length + 3] = e.getREPORT_CODE();
			params[rVals.length + 4] = e.getREPORT_DESC();
			params[rVals.length + 5] = e.getENTITY_FLG();
			params[rVals.length + 6] = e.getMODIFY_FLG();
			params[rVals.length + 7] = e.getDEL_FLG();
			params[rVals.length + 8] = e.getReportDate();
			jdbcTemplate.update(
					"UPDATE BRRS_M_SRWA_12H_DETAILTABLE SET " + R_FIELDS_SET
							+ ",REPORT_VERSION=?,REPORT_RESUBDATE=?,REPORT_FREQUENCY=?,REPORT_CODE=?,REPORT_DESC=?,ENTITY_FLG=?,MODIFY_FLG=?,DEL_FLG=?"
							+ " WHERE REPORT_DATE=?",
					params);
		} else {
			Object[] params = new Object[rVals.length + 9];
			System.arraycopy(rVals, 0, params, 0, rVals.length);
			params[rVals.length] = e.getReportDate();
			params[rVals.length + 1] = e.getReportVersion();
			params[rVals.length + 2] = e.getReportResubDate();
			params[rVals.length + 3] = e.getREPORT_FREQUENCY();
			params[rVals.length + 4] = e.getREPORT_CODE();
			params[rVals.length + 5] = e.getREPORT_DESC();
			params[rVals.length + 6] = e.getENTITY_FLG();
			params[rVals.length + 7] = e.getMODIFY_FLG();
			params[rVals.length + 8] = e.getDEL_FLG();
			jdbcTemplate.update(
					"INSERT INTO BRRS_M_SRWA_12H_DETAILTABLE (REPORT_DATE," + R_COLS
							+ ",REPORT_VERSION,REPORT_RESUBDATE,REPORT_FREQUENCY,REPORT_CODE,REPORT_DESC,ENTITY_FLG,MODIFY_FLG,DEL_FLG) VALUES (?,"
							+ R_PLACEHOLDERS + ",?,?,?,?,?,?,?,?)",
					params);
		}
	}

